#include <stdio.h>
#include <stdlib.h>

int compare(const void *a, const void *b) {
    return (*(int*)a - *(int*)b);
}

int main() {
    int T;
    scanf("%d", &T);
    while (T--) {
        int n, h;
        scanf("%d %d", &n, &h);
        int *t = (int*)malloc(n * sizeof(int));
        for (int i = 0; i < n; i++) {
            scanf("%d", &t[i]);
        }
        int **m = (int**)malloc(n * sizeof(int*));
        for (int i = 0; i < n; i++) {
            m[i] = (int*)malloc(11 * sizeof(int));
            int mx;
            scanf("%d", &mx);
            m[i][0] = mx;
            for (int j = 1; j <= mx; j++) {
                scanf("%d", &m[i][j]);
            }
        }
        int days = 0;
        int time = 0;
        int *stack = (int*)malloc(n * sizeof(int));
        int top = -1;
        stack[++top] = 0;
        while (top >= 0) {
            int x = stack[top--];
            time += t[x];
            if (time > h) {
                time = t[x];
                days++;
            }
            for (int i = 1; i <= m[x][0]; i++) {
                stack[++top] = m[x][i] - 1;
            }
        }
        printf("%d\n", days + 1);
        free(t);
        for (int i = 0; i < n; i++) {
            free(m[i]);
        }
        free(m);
        free(stack);
    }
    return 0;
}

