import java.util.Scanner;
import java.util.Stack;
public class Main {
    public static void main(String[] args) {
        Scanner sc = new Scanner(System.in);
        int T = sc.nextInt();
        while (T-- > 0) {
            int n = sc.nextInt();
            int h = sc.nextInt();
            int[] t = new int[n];
            for (int i = 0; i < n; i++) {
                t[i] = sc.nextInt();
            }
            int[][] m = new int[n][11];
            for (int i = 0; i < n; i++) {
                int mx = sc.nextInt();
                m[i][0] = mx;
                for (int j = 1; j <= mx; j++) {
                    m[i][j] = sc.nextInt();
                }
            }
            int days = 0;
            int time = 0;
            Stack<Integer> stack = new Stack<>();
            stack.push(0);
            while (!stack.isEmpty()) {
                int x = stack.pop();
                time += t[x];
                if (time > h) {
                    time = t[x];
                    days++;
                }
                for (int i = 1; i <= m[x][0]; i++) {
                    stack.push(m[x][i] - 1);
                }
            }
            System.out.println(days + 1);
        }
    }
}

